
(async () => {
  window._uploadResult = 'running';
  try {
    // Assemble base64
    const chunks = ['',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
''];
    const b64 = chunks.join('');
    
    // Decode to Blob
    const binary = atob(b64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const blob = new Blob([bytes], {type: 'image/png'});
    
    // Auth
    const token = await window.Clerk.session.getToken();
    
    // Get presigned URL
    const batchResp = await fetch('https://fnf.higgsfield.ai/media/batch', {
      method: 'POST',
      headers: {'authorization': `Bearer ${token}`, 'content-type': 'application/json'},
      body: JSON.stringify({mimetypes: ['image/png'], source: 'user_upload', surface: 'seedance_2', force_ip_check: true})
    });
    const batchData = await batchResp.json();
    const mediaId = batchData[0].id;
    const presignedUrl = batchData[0].presigned_url;
    
    // Upload to S3
    const putResp = await fetch(presignedUrl, {
      method: 'PUT',
      body: blob,
      headers: {'content-type': 'image/png'}
    });
    
    // Finalize
    const finalResp = await fetch(`https://fnf.higgsfield.ai/media/${mediaId}/upload`, {
      method: 'POST',
      headers: {'authorization': `Bearer ${token}`, 'content-type': 'application/json'},
      body: JSON.stringify({filename: 'meep_v5_final.png', force_nsfw_check: true, force_ip_check: true, surface: 'seedance_2'})
    });
    const finalData = await finalResp.json();
    
    window._uploadResult = {mediaId: mediaId, putStatus: putResp.status, finalStatus: finalResp.status, finalData: finalData};
  } catch(e) {
    window._uploadResult = {error: e.message};
  }
})();
'upload_initiated'
